/* ═══════════════════════════════════════════════════════════
   MONTHLY REFLECTION PRINT FORMAT - CSS
   Compatible with ERPNext Print Format (no grid, tables only)
   Bootstrap 5 utility classes supported
═══════════════════════════════════════════════════════════ */

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');

/* ── RESET & BASE ── */
* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body, .mr-wrapper {
  font-family: 'Inter', 'Segoe UI', Arial, sans-serif;
  font-size: 12px;
  color: #1a1a2e;
  background: #ffffff;
  line-height: 1.6;
}

/* ── WRAPPER ── */
.mr-wrapper {
  max-width: 900px;
  margin: 0 auto;
  padding: 28px 32px;
}

/* ── HEADER TABLE ── */
.header-table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 0;
}

.header-table td {
  vertical-align: middle;
  padding: 0;
}

.logo-cell {
  width: 120px;
}

.company-logo {
  max-width: 110px;
  max-height: 60px;
  object-fit: contain;
}

.logo-placeholder {
  font-size: 18px;
  font-weight: 700;
  color: #1a1a2e;
  letter-spacing: 2px;
}

.title-cell {
  padding-left: 20px;
}

.doc-title {
  font-size: 20px;
  font-weight: 700;
  color: #1a1a2e;
  letter-spacing: 0.3px;
}

.doc-subtitle {
  font-size: 11px;
  color: #6b7280;
  margin-top: 3px;
  font-weight: 400;
  text-transform: uppercase;
  letter-spacing: 0.8px;
}

.ref-cell {
  width: 220px;
  vertical-align: top;
}

/* ── REFERENCE TABLE (top right) ── */
.ref-table {
  width: 100%;
  border-collapse: collapse;
  border: 1px solid #e5e7eb;
  border-radius: 6px;
  overflow: hidden;
}

.ref-table tr:not(:last-child) td {
  border-bottom: 1px solid #e5e7eb;
}

.ref-label {
  background: #f9fafb;
  padding: 5px 10px;
  font-weight: 600;
  color: #374151;
  font-size: 10.5px;
  white-space: nowrap;
  width: 45%;
  border-right: 1px solid #e5e7eb;
}

.ref-value {
  padding: 5px 10px;
  color: #1a1a2e;
  font-size: 10.5px;
}

/* ── STATUS BADGE (pure CSS, colored via Jinja class) ── */
.badge-status {
  display: inline-block;
  padding: 2px 8px;
  border-radius: 20px;
  font-size: 10px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  /* default: draft */
  background: #fef9c3;
  color: #854d0e;
  border: 1px solid #fde68a;
}

.badge-submitted {
  background: #dcfce7;
  color: #166534;
  border-color: #bbf7d0;
}

.badge-approved {
  background: #dbeafe;
  color: #1e40af;
  border-color: #bfdbfe;
}

.badge-rejected {
  background: #fee2e2;
  color: #991b1b;
  border-color: #fecaca;
}

.badge-cancelled {
  background: #f3f4f6;
  color: #6b7280;
  border-color: #e5e7eb;
}

/* ── DIVIDER ── */
.section-divider {
  height: 2px;
  background: linear-gradient(to right, #1a1a2e, #4b5563, #e5e7eb);
  margin: 18px 0 16px 0;
  border-radius: 2px;
}

/* ── SECTION LABEL ── */
.section-label {
  font-size: 10.5px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1.2px;
  color: #ffffff;
  background: #1a1a2e;
  padding: 6px 14px;
  margin-top: 14px;
  margin-bottom: 0;
  border-radius: 4px 4px 0 0;
}

/* ── EMPLOYEE INFO TABLE ── */
.info-table {
  width: 100%;
  border-collapse: collapse;
  border: 1px solid #e5e7eb;
  border-top: none;
  margin-bottom: 0;
}

.info-table tr:not(:last-child) td {
  border-bottom: 1px solid #e5e7eb;
}

.info-key {
  background: #f9fafb;
  padding: 8px 14px;
  font-weight: 600;
  color: #374151;
  font-size: 11px;
  width: 18%;
  border-right: 1px solid #e5e7eb;
  white-space: nowrap;
  vertical-align: top;
}

.info-val {
  padding: 8px 14px;
  color: #1a1a2e;
  font-size: 11px;
  width: 32%;
  border-right: 1px solid #e5e7eb;
  vertical-align: top;
}

.info-val:last-child {
  border-right: none;
}

/* ── CONTENT TABLE (rich text sections) ── */
.content-table {
  width: 100%;
  border-collapse: collapse;
  border: 1px solid #e5e7eb;
  border-top: none;
  margin-bottom: 0;
}

.content-table td {
  padding: 12px 16px;
  color: #1a1a2e;
  font-size: 11.5px;
  line-height: 1.7;
  vertical-align: top;
}

/* ── PLAIN TEXT (feedback / additional comments) ── */
.plain-text {
  white-space: pre-line;
  font-size: 11.5px;
  line-height: 1.7;
}

/* ── RICH TEXT (Quill editor output) ── */
.content-table td h3 {
  font-size: 12px;
  font-weight: 700;
  color: #1a1a2e;
  margin-bottom: 8px;
  display: none; /* hidden since section-label already shows heading */
}

.content-table td p {
  margin-bottom: 6px;
  font-size: 11.5px;
}

.content-table td ol,
.content-table td ul {
  padding-left: 20px;
  margin: 4px 0;
}

.content-table td li {
  margin-bottom: 4px;
  font-size: 11.5px;
}

.content-table td strong {
  font-weight: 600;
  color: #111827;
}

/* ── SIGNATURE TABLE ── */
.signature-table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 12px;
}

.sig-cell {
  vertical-align: top;
  text-align: center;
  width: 30%;
}

.sig-spacer {
  width: 5%;
}

.sig-line {
  height: 1px;
  background: #1a1a2e;
  margin-bottom: 8px;
}

.sig-name {
  font-size: 11px;
  font-weight: 700;
  color: #1a1a2e;
}

.sig-role {
  font-size: 10px;
  color: #6b7280;
  margin-top: 2px;
}

.sig-date {
  font-size: 10px;
  color: #9ca3af;
  margin-top: 6px;
}

/* ── FOOTER TABLE ── */
.footer-table {
  width: 100%;
  border-collapse: collapse;
  border-top: 1px solid #e5e7eb;
  margin-top: 20px;
  padding-top: 8px;
}

.footer-table td {
  padding: 8px 0;
  font-size: 9.5px;
  color: #9ca3af;
}

.footer-left {
  text-align: left;
}

.footer-right {
  text-align: right;
}

/* ── PRINT RULES ── */
@media print {
  .mr-wrapper {
    padding: 16px 20px;
  }

  .section-label {
    -webkit-print-color-adjust: exact;
    print-color-adjust: exact;
  }

  .header-table,
  .info-table,
  .content-table,
  .signature-table,
  .footer-table {
    page-break-inside: avoid;
  }
}
